/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    const targetStr = target.join(',');

    // Helper to convert point array [x, y, z] to a unique string key
    const pointToString = (p) => p.join(',');

    // Helper to calculate the midpoint C = [floor((x1 + x2) / 2), ...]
    const calculateMidpoint = (p1, p2) => {
        const cx = Math.floor((p1[0] + p2[0]) / 2);
        const cy = Math.floor((p1[1] + p2[1]) / 2);
        const cz = Math.floor((p1[2] + p2[2]) / 2);
        return [cx, cy, cz];
    };

    // P_set: Stores string keys of all unique points found so far (P_k)
    const P_set = new Set();
    // P_array: Stores the actual coordinate arrays [x, y, z] for easy pair iteration
    let P_array = [];

    // --- Generation 0 Check ---
    for (const p of points) {
        const pStr = pointToString(p);
        if (pStr === targetStr) {
            return 0;
        }
        if (!P_set.has(pStr)) {
            P_set.add(pStr);
            P_array.push(p);
        }
    }

    let k = 0;

    // --- Iterative Generations (k >= 1) ---
    while (true) {
        k++;
        const newPointsSet = new Set();
        const newPointsArray = [];

        const currentSize = P_array.length;

        if (currentSize < 2) {
            // Cannot form any new pairs if fewer than 2 distinct points exist
            return -1;
        }

        // Generate points for generation k using pairs from P_{k-1} (represented by P_array)
        for (let i = 0; i < currentSize; i++) {
            for (let j = i + 1; j < currentSize; j++) {
                const p1 = P_array[i];
                const p2 = P_array[j];

                const c = calculateMidpoint(p1, p2);
                const cStr = pointToString(c);

                // Only process and store truly new points
                if (!P_set.has(cStr)) {
                    newPointsSet.add(cStr);
                    newPointsArray.push(c);
                }
            }
        }

        // Check for stagnation: If no new points were generated
        if (newPointsArray.length === 0) {
            return -1;
        }

        // Check if the target was generated in this step k
        if (newPointsSet.has(targetStr)) {
            return k;
        }

        // Update state for the next generation
        for (const newPoint of newPointsArray) {
            const newPointStr = pointToString(newPoint);
            P_set.add(newPointStr);
            P_array.push(newPoint);
        }
    }
}

